use std::cmp::Ordering;
use std::collections::BinaryHeap;

// A custom Min-Heap implementation tailored for Dijkstra's requirements:
// Prioritizes minimum time (t), then maximum color (c).
// We store (-t, c, r, c) in a max-heap to simulate min-heap on t and max-heap on c.
// Since Rust's BinaryHeap is a MaxHeap, we want the element with the 'highest' priority 
// according to our custom logic to be at the top.

#[derive(Eq, PartialEq, Clone)]
struct State {
    neg_time: i64, // Store -time to simulate MinHeap on time
    color: i64,    // Store actual color (MaxHeap on color)
    r: i64,
    c: i64,
}

// Implement Ord and PartialOrd such that the element with the highest priority (lowest time, highest color)
// is considered "greater" by the BinaryHeap.
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // 1. Primary comparison: Time. Lower time is better -> higher priority.
        // Since we store -time, a smaller time t results in a larger -t, making it "greater".
        let time_cmp = self.neg_time.cmp(&other.neg_time);
        if time_cmp != Ordering::Equal {
            return time_cmp;
        }

        // 2. Secondary comparison: Color. Higher color is better -> higher priority.
        // Standard comparison works here.
        self.color.cmp(&other.color)
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}


fn solve(n: i64, m: i64, sources: Vec<Vec<i64>>) -> Vec<Vec<i64>> {
    // T[r][c]: Minimum time to reach (r, c). Use a large value for infinity.
    // C[r][c]: Final color of (r, c).

    // We initialize T with a value larger than any possible path length (N*M).
    let infinity: i64 = n * m + 1;

    let mut T = vec![vec![infinity; m as usize]; n as usize];
    let mut C = vec![vec![0; m as usize]; n as usize];

    // Priority Queue stores State: (neg_time, color, r, c)
    let mut pq: BinaryHeap<State> = BinaryHeap::new();

    // Directions for neighbors (Up, Down, Left, Right)
    let directions = vec![
        (-1, 0), (1, 0), (0, -1), (0, 1)
    ];

    // Initialize sources
    for source in sources {
        let r = source[0] as usize;
        let c = source[1] as usize;
        let color = source[2];

        // Initialize sources at time 0
        if T[r][c] == infinity {
            T[r][c] = 0;
            C[r][c] = color;

            // Push: State = (-time, color, r, c)
            pq.push(State { 
                neg_time: 0, 
                color: color, 
                r: r as i64, 
                c: c as i64 
            });
        }
    }

    // Dijkstra's Algorithm
    while let Some(State { neg_time, color: current_color, r: r_i64, c: c_i64 }) = pq.pop() {
        let r = r_i64 as usize;
        let c = c_i64 as usize;
        let t = -neg_time;

        // Check for stale entries or suboptimal paths discovered earlier
        // If the recorded time is strictly less, this entry is stale.
        if t > T[r][c] {
            continue;
        }
        // If times are equal, but the recorded color is strictly better, this entry is stale.
        if t == T[r][c] && current_color < C[r][c] {
            continue;
        }


        // Spread to neighbors
        for (dr, dc) in &directions {
            let nr = r_i64 + dr;
            let nc = c_i64 + dc;

            // Check bounds
            if nr >= 0 && nr < n && nc >= 0 && nc < m {
                let nr_usize = nr as usize;
                let nc_usize = nc as usize;

                let next_t = t + 1;
                let next_c = current_color;

                // Relaxation condition:
                let current_T = T[nr_usize][nc_usize];
                let current_C = C[nr_usize][nc_usize];

                let improved = false;

                // 1. Strictly better time found.
                if next_t < current_T {
                    T[nr_usize][nc_usize] = next_t;
                    C[nr_usize][nc_usize] = next_c;
                    pq.push(State { 
                        neg_time: -next_t, 
                        color: next_c, 
                        r: nr, 
                        c: nc 
                    });
                    improved = true;
                } 
                // 2. Same minimum time found, but better color.
                else if next_t == current_T {
                    if next_c > current_C {
                        C[nr_usize][nc_usize] = next_c;
                        // Since the color improved at the minimum time, we must propagate this better color
                        pq.push(State { 
                            neg_time: -next_t, 
                            color: next_c, 
                            r: nr, 
                            c: nc 
                        });
                        improved = true;
                    }
                }
                // If the cell is already colored (current_T < infinity), and we didn't improve it, we do nothing.
            }
        }
    }

    // Return the final color grid C
    C
}

