/**
 * Helper class for a MinPriorityQueue implementation required for Dijkstra's algorithm.
 * Stores elements as [time, negative_color, r, c].
 * Comparison prioritizes smaller time, then smaller negative_color (i.e., larger color).
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    size() {
        return this.heap.length;
    }

    _parent(i) { return Math.floor((i - 1) / 2); }
    _leftChild(i) { return 2 * i + 1; }
    _rightChild(i) { return 2 * i + 2; }

    _compare(a, b) {
        // a and b are [t, neg_c, r, c]
        if (a[0] !== b[0]) {
            return a[0] - b[0]; // Compare time (t) first (Min Heap)
        }
        return a[1] - b[1]; // Compare negative color (-c) second (Min Heap on -c means Max Heap on c)
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    push(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    pop() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return root;
    }

    _bubbleUp(i) {
        let currentIndex = i;
        while (currentIndex > 0) {
            const parentIndex = this._parent(currentIndex);
            if (this._compare(this.heap[currentIndex], this.heap[parentIndex]) < 0) {
                this._swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    _bubbleDown(i) {
        let currentIndex = i;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let smallest = currentIndex;
            const left = this._leftChild(currentIndex);
            const right = this._rightChild(currentIndex);

            if (left <= lastIndex && this._compare(this.heap[left], this.heap[smallest]) < 0) {
                smallest = left;
            }
            if (right <= lastIndex && this._compare(this.heap[right], this.heap[smallest]) < 0) {
                smallest = right;
            }

            if (smallest !== currentIndex) {
                this._swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }
}


function solve(n, m, sources) {
    // T[r][c]: Minimum time to reach (r, c)
    // C[r][c]: Final color of (r, c)

    // Initialize grids
    const T = Array(n).fill(0).map(() => Array(m).fill(Infinity));
    const C = Array(n).fill(0).map(() => Array(m).fill(0));

    // Priority Queue stores [time, negative_color, r, c]
    const pq = new MinPriorityQueue();

    // Directions for neighbors (Up, Down, Left, Right)
    const directions = [[-1, 0], [1, 0], [0, -1], [0, 1]];

    // Initialize sources
    for (const source of sources) {
        const r = source[0];
        const c = source[1];
        const color = source[2];

        // Since sources start at time 0, they define the initial state
        if (T[r][c] > 0) { // Handle potential duplicate source positions if constraints allowed it, but here it's safe.
            T[r][c] = 0;
            C[r][c] = color;
            // Push: [time, -color, r, c]
            pq.push([0, -color, r, c]);
        }
    }

    // Dijkstra's Algorithm
    while (!pq.isEmpty()) {
        const [t, neg_c, r, c] = pq.pop();
        const currentColor = -neg_c;

        // Check for stale entries. If the grid state has already been optimized beyond what this entry suggests, skip.
        // This check is crucial because we might push multiple entries for the same cell (r, c) 
        // if a better color reached it at the same minimum time T, or a better T arrived later.
        if (t > T[r][c] || (t === T[r][c] && currentColor < C[r][c])) {
            continue;
        }

        // Spread to neighbors
        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const nextT = t + 1;
                const nextC = currentColor;

                // Relaxation condition:
                // 1. Strictly better time found.
                if (nextT < T[nr][nc]) {
                    T[nr][nc] = nextT;
                    C[nr][nc] = nextC;
                    pq.push([nextT, -nextC, nr, nc]);
                } 
                // 2. Same minimum time found, but better color.
                else if (nextT === T[nr][nc]) {
                    if (nextC > C[nr][nc]) {
                        C[nr][nc] = nextC;
                        // Since the color improved at the minimum time, we must propagate this better color
                        pq.push([nextT, -nextC, nr, nc]);
                    }
                }
            }
        }
    }

    // The grid C now holds the final state
    return C;
}

